import type { DiscoverOriginSchemaSuccess } from '@agentcash/discovery';

import { discoverResources } from '@/operations/discover';
import { errorResponse } from '@/cli/output';

import type z from 'zod';
import type { discoverResourcesSchema } from '@/operations/discover';

export interface ResolvedOrigin {
  url: string;
  title: string;
  description: string;
  warnings: string[];
}

/**
 * Normalize a URL, validate it, and discover its OpenAPI spec.
 * Shared by `agentcash add` and `agentcash origins add`.
 */
export async function resolveOrigin(
  surface: string,
  args: z.input<typeof discoverResourcesSchema>
) {
  const result = await discoverResources(surface, args);

  if (!result.found) {
    return {
      ok: false as const,
      error: errorResponse({
        code: 'GENERAL_ERROR',
        message: result.message ?? `No OpenAPI spec found for ${result.origin}`,
        surface,
        cause: result.cause,
      }),
    };
  }

  const description = resolveDescription(result) ?? '';

  const warnings: string[] = [];
  if (!result.info?.title)
    warnings.push('No title found in OpenAPI spec; derived from URL.');
  if (!result.info?.description)
    warnings.push(
      description
        ? 'No description found in OpenAPI spec; derived from guidance.'
        : 'No description could be found.'
    );

  return {
    ok: true as const,
    origin: {
      url: result.origin,
      title: resolveTitle(result),
      description,
      warnings,
    },
  };
}

/**
 * Derive a display title for an origin. Uses the OpenAPI info title if present,
 * otherwise falls back to the hostname with www. stripped and the TLD removed
 * (e.g. "stableenrich.dev" → "stableenrich").
 */
function resolveTitle(result: DiscoverOriginSchemaSuccess): string {
  if (result.info?.title) return result.info.title;
  const hostname = new URL(result.origin).hostname.replace(/^www\./, '');
  const parts = hostname.split('.');
  return parts.length > 1 ? parts.slice(0, -1).join('.') : hostname;
}

/**
 * Resolve a description for an origin. Uses the OpenAPI/well-known info description if
 * present, otherwise falls back to the first 100 characters of guidance.
 * Returns null if neither is available.
 */
function resolveDescription(
  result: DiscoverOriginSchemaSuccess
): string | null {
  if (result.info?.description) return result.info.description;
  if (result.guidance) return result.guidance.slice(0, 100);
  return null;
}
